import{_ as a,o as t,c as o,a6 as i}from"./chunks/framework.DtxWasON.js";const u=JSON.parse('{"title":"OoO Data API Guide","description":"","frontmatter":{},"headers":[],"relativePath":"ooo/guide/ooo_api.md","filePath":"ooo/guide/ooo_api.md"}'),s={name:"ooo/guide/ooo_api.md"};function r(n,e,d,c,l,h){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="ooo-data-api-guide" tabindex="-1">OoO Data API Guide <a class="header-anchor" href="#ooo-data-api-guide" aria-label="Permalink to &quot;OoO Data API Guide&quot;">​</a></h1><p>This guide covers the data available via the OoO API, requested through the xFUND Router network. The going-forward API queries decentralised-exchange (DEX) liquidity pools for a pair&#39;s price. The legacy Finchains price API (request type <code>PR</code>) has been <strong>removed</strong>; <code>PR</code> requests are now redirected to the DEX path (see <a href="#legacy-finchains-api-pr">Legacy Finchains API</a>).</p><h2 id="data-providers" tabindex="-1">Data Providers <a class="header-anchor" href="#data-providers" aria-label="Permalink to &quot;Data Providers&quot;">​</a></h2><p>See <a href="./../providers.html">Providers</a> for the Oracles providing data on each supported network, along with their associated fees and wallet addresses. To run your own provider oracle, see <a href="./run-provider.html">Running an OoO Data Provider</a>.</p><div class="tip custom-block"><p class="custom-block-title">Note</p><p>OoO data providers may wait for 2 - 3 or more block confirmations before processing a request. Depending on network congestion and gas prices, it may therefore take up to a minute or more for data to be sent to your smart contract from the time your request Tx was received by the provider oracle.</p></div><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>Data is acquired via the OoO API using dot-separated strings to define the pair to price - for example the mean <code>WETH/USDC</code> price over the last 30 minutes is requested using <code>WETH.USDC.30</code>.</p><p>The hex-encoded string is supplied along with the Provider address (as defined above, depending on the network) and the <code>xFUND</code> fee as parameters to your smart contract, using the <a href="./implementation.html#_3-1-requestdata">requestdata</a> function you defined.</p><p>The OoO Data Provider picks up this request, and supplies the data via the <a href="./implementation.html#_3-2-recievedata">recievedata</a> function you defined.</p><h2 id="request-string-format" tabindex="-1">Request String Format <a class="header-anchor" href="#request-string-format" aria-label="Permalink to &quot;Request String Format&quot;">​</a></h2><p>The canonical, going-forward request format is:</p><p><code>BASE.TARGET[.MINUTES]</code></p><p><code>BASE</code> and <code>TARGET</code> are required. <code>MINUTES</code> is an optional AdHoc lookback window (an integer from <code>0</code> to <code>60</code>). Every request of this form is a DEX price query - see <a href="#dex-price-queries">DEX price queries</a> below.</p><div class="tip custom-block"><p class="custom-block-title">NOTE</p><p>The data request string should be converted to a <code>Bytes32</code> (Hex) value before submitting it to your smart contract&#39;s request function, for example:</p><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> endpoint</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> web3.utils.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">asciiToHex</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;WETH.USDC&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> endpoint</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> web3.utils.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">asciiToHex</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;WETH.USDC.30&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> etc.</span></span></code></pre></div></div><div class="warning custom-block"><p class="custom-block-title">DEPRECATED</p><p>The legacy explicit-type forms <code>BASE.TARGET.AD[.MINUTES]</code> (DEX/AdHoc) and <code>BASE.TARGET.PR.SUBTYPE[...]</code> (<a href="#legacy-finchains-api-pr">Finchains</a>) are still accepted but <strong>deprecated</strong>. New consumers should use the suffix-less form above; the <code>AD</code>/<code>PR</code> parsing will be removed once live usage drops to zero. Any trailing fields a DEX query cannot honour (such as a leftover Finchains <code>SUBTYPE</code>) are ignored, and the price is still returned from the DEX mean.</p></div><h3 id="base" tabindex="-1">BASE <a class="header-anchor" href="#base" aria-label="Permalink to &quot;BASE&quot;">​</a></h3><p>The symbol for the base currency for which the price will be returned, e.g. <code>WETH</code>, <code>xFUND</code>, <code>ETH</code> etc.</p><h3 id="target" tabindex="-1">TARGET <a class="header-anchor" href="#target" aria-label="Permalink to &quot;TARGET&quot;">​</a></h3><p>The symbol for the target currency in which to return the price, e.g. <code>USDC</code>, <code>WETH</code>, <code>USD</code>.</p><p>For DEX queries the supported pairs are those listed by the supported DEXs - see <a href="#dex-price-queries">DEX price queries</a> below.</p><h2 id="dex-price-queries" tabindex="-1">DEX price queries <a class="header-anchor" href="#dex-price-queries" aria-label="Permalink to &quot;DEX price queries&quot;">​</a></h2><p>Every canonical request (<code>BASE.TARGET[.MINUTES]</code>) is served as a DEX price query. The provider <strong>attempts</strong> to query the supported DEXs&#39; subgraphs to determine whether the <code>BASE</code> and <code>TARGET</code> symbols are known to the DEX, and whether the DEX has a liquidity pool representing the pair. For every DEX that lists the pair it retrieves the latest price, then calculates the mean across all results, removing outliers with the Chauvenet criterion where there is enough data to do so.</p><p>The supported DEXs and pairs are curated and published by the <a href="https://ooo-dex.unification.io" target="_blank" rel="noreferrer">dex-pair-verify</a> catalogue, which the provider oracle syncs from. They span the major EVM DEX families across several chains — including Uniswap (v2/v3/v4), Sushiswap, Shibaswap, Quickswap, Pancakeswap and Honeyswap — as well as non-EVM sources such as Osmosis on Cosmos. The catalogue is curated and grows over time, so treat the live browser as the source of truth rather than any fixed list here.</p><p><strong>Browse the currently supported pairs, DEXs and networks at <a href="https://ooo-dex.unification.io" target="_blank" rel="noreferrer">https://ooo-dex.unification.io</a>.</strong></p><div class="danger custom-block"><p class="custom-block-title">IMPORTANT</p><p><code>BASE</code> and <code>TARGET</code> are <strong>CaSe SeNsItIvE</strong>! <code>XFUND</code> is <strong>not</strong> the same as <code>xFUND</code>. <strong>Always check your request endpoints, and that at least one DEX supports the pair before sending a data request!</strong></p></div><h3 id="minutes" tabindex="-1"><code>MINUTES</code> <a class="header-anchor" href="#minutes" aria-label="Permalink to &quot;`MINUTES`&quot;">​</a></h3><p>The optional third field sets the lookback window, as an integer from <code>0</code> to <code>60</code>. The default is <code>0</code>, which tells the oracle to fetch only the latest prices. A non-zero value tells the oracle to fetch prices over the past <code>nn</code> minutes and average them.</p><p><strong>Example</strong></p><p>We know the <code>xFUND/WETH</code> pair is listed on Uniswap v2 and Shibaswap, and we&#39;d like the mean price over the last 30 minutes:</p><p><code>xFUND.WETH.30</code></p><p>The provider picks up the request, queries the supported DEXs that list the pair for the last 30 minutes of prices, and returns the mean (outliers removed with the Chauvenet criterion).</p><div class="tip custom-block"><p class="custom-block-title">Legacy <code>.AD</code></p><p>The explicit <code>BASE.TARGET.AD[.MINUTES]</code> form (e.g. <code>xFUND.WETH.AD.30</code>) is the deprecated alias of the canonical form and is still accepted. Prefer the suffix-less form for new integrations.</p></div><h2 id="legacy-finchains-api-pr" tabindex="-1">Legacy Finchains API (<code>PR</code>) <a class="header-anchor" href="#legacy-finchains-api-pr" aria-label="Permalink to &quot;Legacy Finchains API (`PR`)&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">REMOVED</p><p>The Finchains price API (request type <code>PR</code>) has been <strong>removed</strong> - Finchains is no longer queried.</p><p>For backward compatibility, the provider <strong>lossily redirects</strong> a legacy <code>BASE.TARGET.PR.SUBTYPE[...]</code> request to the DEX price path on <code>BASE.TARGET</code> alone: the Finchains qualifiers (<code>SUBTYPE</code>, time window, per-exchange filter) are <strong>silently dropped</strong> and the price is served as the <a href="#dex-price-queries">DEX mean</a>. If <code>BASE.TARGET</code> is not available on any supported DEX, the request returns a clear error and is <strong>not</strong> fulfilled.</p><p><strong>Migrate to the suffix-less form</strong> <code>BASE.TARGET[.MINUTES]</code>. The <code>PR</code> parsing itself will be removed once live usage drops to zero. Note that DEX prices come from on-chain liquidity pools, not the former centralised-exchange aggregation, so a redirected price may differ from the old Finchains value.</p></div><h2 id="return-data" tabindex="-1">Return data <a class="header-anchor" href="#return-data" aria-label="Permalink to &quot;Return data&quot;">​</a></h2><p>All price data is supplied by the Oracle as <code>actualPrice * (10 ^ 18)</code> to standardise decimal removal, and allow integer calculations in smart contracts.</p><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2><p>Canonical (going-forward) requests:</p><ul><li><code>WETH.USDC</code>: latest mean WETH/USDC price from all supported DEXs.</li><li><code>WETH.USDC.30</code>: mean WETH/USDC price over the last 30 minutes.</li><li><code>COOL.WETH</code>: latest mean COOL/WETH price from all supported DEXs.</li></ul><p>Legacy (deprecated) forms:</p><ul><li><code>COOL.WETH.AD</code>: explicit AdHoc alias of <code>COOL.WETH</code>.</li><li><code>BTC.GBP.PR.AVG</code>: a legacy Finchains-shape request - redirected to the DEX path on <code>BTC.GBP</code> (qualifiers dropped), or an error if that pair is on no supported DEX.</li><li><code>ETH.USD.PR.AVI.24H</code>: likewise redirected to the DEX path on <code>ETH.USD</code> (qualifiers dropped).</li></ul>',41)])])}const E=a(s,[["render",r]]);export{u as __pageData,E as default};
